from dataclasses import dataclass, field
from datetime import date
from typing import Literal
import yaml, json
from pathlib import Path

RiskCategory = Literal["data_privacy", "model_quality", "operational", "legal", "reputational"]
RiskStatus = Literal["open", "mitigated", "accepted", "transferred"]

@dataclass
class RiskEntry:
    risk_id: str
    category: RiskCategory
    title: str
    description: str
    likelihood: int           # 1–5
    impact: int               # 1–5
    controls: list[str]
    residual_likelihood: int  # 1–5 after controls
    residual_impact: int      # 1–5 after controls
    owner: str
    review_date: date
    status: RiskStatus = "open"

    @property
    def inherent_score(self) -> int:
        return self.likelihood * self.impact

    @property
    def residual_score(self) -> int:
        return self.residual_likelihood * self.residual_impact

    def to_dict(self) -> dict:
        d = self.__dict__.copy()
        d["inherent_score"] = self.inherent_score
        d["residual_score"] = self.residual_score
        d["review_date"] = str(self.review_date)
        return d


REGISTER_PATH = Path("governance/ai_risk_register.yaml")

def load_register() -> list[RiskEntry]:
    data = yaml.safe_load(REGISTER_PATH.read_text())
    return [RiskEntry(**r) for r in data["risks"]]

def save_register(entries: list[RiskEntry]) -> None:
    data = {"risks": [e.to_dict() for e in entries]}
    REGISTER_PATH.write_text(yaml.dump(data, sort_keys=False, allow_unicode=True))

def validate_register(entries: list[RiskEntry]) -> list[str]:
    """Return a list of validation errors."""
    errors = []
    ids = [e.risk_id for e in entries]
    if len(ids) != len(set(ids)):
        errors.append("Duplicate risk_id values found")
    for e in entries:
        if not (1 <= e.likelihood <= 5):
            errors.append(f"{e.risk_id}: likelihood {e.likelihood} out of range")
        if not (1 <= e.impact <= 5):
            errors.append(f"{e.risk_id}: impact {e.impact} out of range")
        if not e.owner:
            errors.append(f"{e.risk_id}: owner is required")
        if not e.controls:
            errors.append(f"{e.risk_id}: at least one control is required")
    return errors

from datetime import date

def steering_committee_report(
    current: list["RiskEntry"],
    previous_snapshot: list["RiskEntry"],
    report_date: date,
) -> dict:
    """
    Produce a quarterly change report comparing current register to previous snapshot.
    """
    prev_map = {e.risk_id: e for e in previous_snapshot}
    curr_map = {e.risk_id: e for e in current}

    new_risks = [e for rid, e in curr_map.items() if rid not in prev_map]
    closed_risks = [e for rid, e in prev_map.items() if rid not in curr_map]
    score_changes = [
        {
            "risk_id": rid,
            "title": curr_map[rid].title,
            "prev_residual": prev_map[rid].residual_score,
            "curr_residual": curr_map[rid].residual_score,
            "delta": curr_map[rid].residual_score - prev_map[rid].residual_score,
        }
        for rid in curr_map
        if rid in prev_map and curr_map[rid].residual_score != prev_map[rid].residual_score
    ]
    escalated = [e for e in current if classify_residual(e) == "escalate"]

    return {
        "report_date": str(report_date),
        "total_open": sum(1 for e in current if e.status == "open"),
        "new_risks": [{"risk_id": e.risk_id, "title": e.title, "residual": e.residual_score}
                      for e in new_risks],
        "closed_risks": [{"risk_id": e.risk_id, "title": e.title} for e in closed_risks],
        "score_changes": score_changes,
        "escalated_risks": [{"risk_id": e.risk_id, "title": e.title, "score": e.residual_score}
                             for e in escalated],
        "appetite_summary": appetite_report(current),
    }
